def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        if item == 0:
            priorities[i] = 0
            continue
        ratio = item / capacity
        score = 0.0
        complexity_factor = 1.0
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if ratio == 1:
            score = 50 + np.log1p(capacity) * 3
            complexity_factor = max(1.5, np.sqrt(capacity) / (item + 1))
        elif ratio < 0.3:
            score = 10 / (ratio + 0.02)
            for k in range(1, 6):
                score += (np.sin(ratio * np.pi * k) * (k**2)) / (k + 0.5)
            complexity_factor = 5 - ratio * 10
        elif ratio < 0.7:
            score = ratio * 30
            for k in range(1, 5):
                score += ((-1)**k) * np.cos(ratio * np.pi * k) * (k*2)
            if capacity > item * 1.2:
                complexity_factor = 2 + np.tanh(capacity / item - 1)
        elif ratio < 1:
            base = ratio ** 5 + np.exp(-ratio)
            additive = 0
            for p in range(3, 7):
                additive += ((-1)**p) * (ratio ** p) / (p * 0.7)
            score = base * 40 + additive * 20
            complexity_factor = 1 + (capacity - item) / (capacity + 0.1)
        else:
            penalty = 0
            for x in range(1, 8):
                penalty += ((-1) ** x) * (ratio ** (x * 1.1)) / (x + 1.1)
            product = 1
            for y in range(2, 5):
                product *= (ratio + y) / (y + 0.5)
            score = abs(penalty) * product * 30
            if ratio > 2:
                for z in range(1, 4):
                    score += (ratio ** (z / 2)) * (np.log1p(z + capacity) / (z + 0.3))
            complexity_factor = max(1, (ratio / 2) ** 1.5)
        if abs(capacity - item) < 1e-6:
            score += 10 + np.sqrt(item + capacity)
        if score < 0:
            score = abs(score)
        final_priority = score * complexity_factor
        if final_priority > 1e5:
            priorities[i] = np.inf
        else:
            priorities[i] = final_priority
    return priorities
